<template>
    <div class="container">
      <div v-for="(title, index) in titles" :key="index" class="custom-cell" @click="gotoMarkdown(index)">
        <div class="title">{{ title }}</div>
        <div class="label">更新时间：{{ updateTimes[index] }}</div>
      </div>
      <van-tabbar v-model="active">
        <van-tabbar-item icon="home-o" :to="{ name: 'FrontView' }">杂七杂八的踩坑</van-tabbar-item>
        <van-tabbar-item icon="desktop-o" :to="{ name: 'BackDevView' }">后端开发</van-tabbar-item>
        <van-tabbar-item icon="edit" :to="{ name: 'AlgorithmView' }">算法</van-tabbar-item>
        <van-tabbar-item icon="manager-o" :to="{ name: 'mineView' }">我的</van-tabbar-item>
      </van-tabbar>
    </div>
  </template>
  
  <script>
  import axios from 'axios';
  
  export default {
    data() {
      return {
        titles: [],
        updateTimes: [],
        active: 0,
      };
    },
    created() {
      axios.get("https://gitee.com/lysssyo/FrontIndex/raw/main/Index.md")
        .then(resp => {
          this.index = resp.data; //响应数据赋值给数据模型
          console.log("This.index=" + this.index);
  
          // 使用正则表达式匹配标题和更新时间，并存储到相应的数组中
          this.index.replace(/Tittle：(.*?)\n/g, (match, title) => {
            this.titles.push(title.trim());
          });
  
          this.index.replace(/UpdateTime：(.*?)\n/g, (match, updateTime) => {
            this.updateTimes.push(updateTime.trim());
          });
  
          console.log("Titles:", this.titles);
          console.log("Update Times:", this.updateTimes);
        })
        .catch(error => {
          console.error('Error fetching data:', error);
        });
    },
    methods: {

    }
  };
  </script>
  

  <style scoped>
  .container {
    border-top: 1px solid #000;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: flex-start;
    height: 100%;
    padding-top: 10px;
    padding-bottom: 140px;
  }
  
  .custom-cell {
    width: 90%; /* 设置单元格宽度 */
    margin: 3px; /* 设置单元格间距 */
    border-radius: 10px; /* 设置单元格边框圆角 */
    padding: 10px; /* 设置内边距 */
    background-color: #ffffff; /* 设置背景颜色 */
    box-shadow: 0px 2px 4px rgba(0, 0, 0, 0.1); /* 设置阴影 */
    cursor: pointer; /* 设置鼠标样式 */
  }
  
  .title {
    font-weight: bold; /* 设置标题加粗 */
    font-size: 16px;
    color: #333; /* 设置标题颜色 */
    padding-bottom: 3px;
  }
  
  .label {
    font-size: 14px; /* 设置标签字体大小 */
    color: #666; /* 设置标签颜色 */
  }
  </style>
    
  
  